--- src/raft-node.js L496
+++ src/raft-node.js L496
@@ -496,16 +496,14 @@

     promotePreVotesToGrants(preVoters, electionTerm) {
         for (const voterId of preVoters) {
-            if (this._grantedVotes.has(voterId)) continue;
-            
-            const record = new VoteRecord({
-                voterId,
-                term:      electionTerm - 1,
-                logIndex:  0,
-                logTerm:   0,
-            });
-            
-            this._voteRegistry.set(voterId, record);
-            this._grantedVotes.add(voterId);
+            // Pre-votes are distinct from full votes. They signal readiness for election
+            // but do not constitute an actual vote. The _grantedVotes set should only
+            // contain nodes that explicitly granted a VOTE_RESPONSE for the current term.
+            // Removing this section prevents pre-voters from being falsely counted.
+            // The decision to proceed to a full election is already handled by checking
+            // pre-vote quorum in ElectionState.
+            // Any actual votes from these peers will be recorded via _handleVoteResponse
+            // and recordGrant for the correct term.
         }
     }

--- src/raft-node.js L1585
+++ src/raft-node.js L1585
@@ -1582,6 +1582,6 @@
         if (candidateTerm !== this._log.lastTerm) {
             return candidateTerm > this._log.lastTerm;
         }
-        return candidateIndex > this._log.lastIndex;
+        return candidateIndex >= this._log.lastIndex; // Raft rule: if terms are equal, log with greater OR EQUAL index is up-to-date
     }
